// AI Production Operations Copilot - Scheduled Alert Generator
//
// UPDATE THESE TWO VALUES AFTER IMPORTING:
// 1. targetWebhookUrl: the production webhook URL for the main Alert Triage workflow.
// 2. approvalBaseUrl: the production webhook URL for the Approval Handler workflow.
//
// For local testing, you can use webhook-test URLs only while manually executing workflows.

const config = {
  targetWebhookUrl: 'https://oyeolatunji.app.n8n.cloud/webhook/ops-copilot-alert',
  approvalBaseUrl: 'https://oyeolatunji.app.n8n.cloud/webhook/ops-copilot-approval',
  source: 'scheduled-demo-generator',
  environment: 'prod'
};

const staticData = $getWorkflowStaticData('global');
staticData.runCount = (staticData.runCount || 0) + 1;

const now = new Date();
const timestamp = now.toISOString();
const suffix = `${now.toISOString().replace(/[-:.TZ]/g, '').slice(0, 14)}-${staticData.runCount}`;

const scenarios = [
  {
    title: 'High latency and error rate on booking-transformer',
    service: 'booking-transformer',
    severity: 'critical',
    description: 'P95 latency and 5xx rate exceeded threshold after recent deployment',
    metrics: {
      p95LatencyMs: 2400,
      p99LatencyMs: 5100,
      errorRatePercent: 12.5,
      throughputRps: 460,
      saturationPercent: 91
    },
    logs: [
      'ERROR timeout calling downstream inventory-api after 2000ms',
      'WARN retry attempt=3 correlationId=demo-123',
      'ERROR circuit breaker open for dependency=inventory-api'
    ]
  },
  {
    title: 'Kafka consumer lag increasing on payment-events-consumer',
    service: 'payment-events-consumer',
    severity: 'high',
    description: 'Consumer lag is growing faster than processing throughput, creating delayed payment status updates',
    metrics: {
      p95LatencyMs: 850,
      p99LatencyMs: 1700,
      errorRatePercent: 3.8,
      throughputRps: 220,
      saturationPercent: 84,
      kafkaConsumerLag: 18500
    },
    logs: [
      'WARN consumer lag above threshold topic=payment-events partition=4 lag=18500',
      'ERROR failed to deserialize event schemaVersion=7 expected=6',
      'WARN retrying message offset=827193 attempt=2'
    ]
  },
  {
    title: 'Database connection pool saturation on customer-profile-api',
    service: 'customer-profile-api',
    severity: 'high',
    description: 'Database pool utilization is near max and API latency is degrading for customer profile lookups',
    metrics: {
      p95LatencyMs: 1900,
      p99LatencyMs: 4200,
      errorRatePercent: 7.2,
      throughputRps: 310,
      saturationPercent: 96,
      dbPoolUtilizationPercent: 98
    },
    logs: [
      'WARN HikariPool connection wait timeout after 30000ms',
      'ERROR SQLTransientConnectionException connection is not available',
      'WARN slow query detected durationMs=2840 table=customer_profile'
    ]
  },
  {
    title: 'Payment provider timeout spike on checkout-service',
    service: 'checkout-service',
    severity: 'medium',
    description: 'External payment provider calls are timing out intermittently, increasing checkout failure rate',
    metrics: {
      p95LatencyMs: 3100,
      p99LatencyMs: 7600,
      errorRatePercent: 5.6,
      throughputRps: 145,
      saturationPercent: 72,
      externalDependencyTimeouts: 94
    },
    logs: [
      'ERROR provider=payment-gateway request timed out after 5000ms',
      'WARN fallback payment status set to PENDING correlationId=pay-9921',
      'WARN circuit breaker half-open for payment-gateway'
    ]
  },
  {
    title: 'Memory pressure and pod restarts on recommendation-service',
    service: 'recommendation-service',
    severity: 'medium',
    description: 'Container memory usage is close to limit and Kubernetes has restarted pods multiple times',
    metrics: {
      p95LatencyMs: 1200,
      p99LatencyMs: 2800,
      errorRatePercent: 2.9,
      throughputRps: 380,
      saturationPercent: 89,
      memoryUsagePercent: 94,
      podRestartCount: 3
    },
    logs: [
      'WARN JVM heap usage above 90 percent',
      'ERROR pod restarted reason=OOMKilled previousExitCode=137',
      'WARN GC pause durationMs=740'
    ]
  }
];

const scenario = scenarios[(staticData.runCount - 1) % scenarios.length];

const payload = {
  incidentId: `inc-demo-${suffix}`,
  source: config.source,
  title: scenario.title,
  service: scenario.service,
  environment: config.environment,
  severity: scenario.severity,
  description: scenario.description,
  metrics: scenario.metrics,
  logs: scenario.logs,
  approvalBaseUrl: config.approvalBaseUrl,
  demoMetadata: {
    generatedAt: timestamp,
    scheduleRunCount: staticData.runCount,
    scenarioNumber: ((staticData.runCount - 1) % scenarios.length) + 1,
    workflowPurpose: 'Scheduled demo trigger for AI Production Operations Copilot'
  }
};

return [
  {
    json: {
      targetWebhookUrl: config.targetWebhookUrl,
      payload
    }
  }
];

const response = $input.first().json;

return [
  {
    json: {
      status: 'scheduled-alert-generator-finished',
      httpStatusCode: response.statusCode || response.status || 'unknown',
      copilotResponse: response.body || response,
      checkedAt: new Date().toISOString(),
      note: 'If this failed, confirm the main Alert Triage workflow is active and targetWebhookUrl points to /webhook/ops-copilot-alert, not /webhook-test unless testing manually.'
    }
  }
];
